{{-- Guía de tallas modal — Theme Ropa --}}
<div id="ec-size-guide-modal" style="display:none;position:fixed;inset:0;z-index:1060;background:rgba(0,0,0,.5)">
    <div style="background:#fff;max-width:600px;margin:80px auto;border-radius:12px;padding:24px;max-height:80vh;overflow-y:auto">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">
            <h3 style="font-size:18px;font-weight:700;margin:0">Guía de Tallas</h3>
            <button onclick="document.getElementById('ec-size-guide-modal').style.display='none'" style="background:none;border:none;font-size:24px;cursor:pointer">&times;</button>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:13px">
            <thead>
                <tr style="background:#f3f4f6">
                    <th style="padding:10px;text-align:left;border-bottom:2px solid #e5e7eb">Talla</th>
                    <th style="padding:10px;text-align:center;border-bottom:2px solid #e5e7eb">Pecho (cm)</th>
                    <th style="padding:10px;text-align:center;border-bottom:2px solid #e5e7eb">Cintura (cm)</th>
                    <th style="padding:10px;text-align:center;border-bottom:2px solid #e5e7eb">Cadera (cm)</th>
                </tr>
            </thead>
            <tbody>
                <tr><td style="padding:8px;border-bottom:1px solid #f3f4f6;font-weight:600">XS</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">80-84</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">60-64</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">86-90</td></tr>
                <tr><td style="padding:8px;border-bottom:1px solid #f3f4f6;font-weight:600">S</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">84-88</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">64-68</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">90-94</td></tr>
                <tr><td style="padding:8px;border-bottom:1px solid #f3f4f6;font-weight:600">M</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">88-92</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">68-72</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">94-98</td></tr>
                <tr><td style="padding:8px;border-bottom:1px solid #f3f4f6;font-weight:600">L</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">92-96</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">72-76</td><td style="padding:8px;text-align:center;border-bottom:1px solid #f3f4f6">98-102</td></tr>
                <tr><td style="padding:8px;font-weight:600">XL</td><td style="padding:8px;text-align:center">96-100</td><td style="padding:8px;text-align:center">76-80</td><td style="padding:8px;text-align:center">102-106</td></tr>
            </tbody>
        </table>
        <p style="font-size:11px;color:#9ca3af;margin-top:12px">* Las medidas pueden variar según el diseño. Si estás entre dos tallas, te recomendamos elegir la más grande.</p>
    </div>
</div>
